#include "hip/hip_runtime.h"
// Optimized ball_query kernel with LDS tiling, SoA layout
// Each block handles BLOCK_SIZE query points, cooperatively loading source point tiles into LDS

#include <math.h>
#include <stdio.h>
#include <stdlib.h>

#include <c10/cuda/CUDAStream.h>
#include <ATen/cuda/CUDAApplyUtils.cuh>

#define DIVUP(m, n) ((m) / (n) + ((m) % (n) > 0))

// Tile size for source points loaded into LDS (SoA layout)
#define TILE_SIZE 512
// Each block has BLOCK_SIZE threads
#define BLOCK_SIZE 256

// Fixed radius kernel (min_radius == 0)
__global__ __launch_bounds__(BLOCK_SIZE)
void ball_query_kernel_fixed(int b, int n, int m,
                              float max_radius2,
                              int nsample,
                              const float *__restrict__ new_xyz,
                              const float *__restrict__ xyz,
                              int *__restrict__ idx) {
  int bs_idx = blockIdx.y;
  if (bs_idx >= b) return;

  int tid = threadIdx.x;
  int query_idx = blockIdx.x * BLOCK_SIZE + tid;

  // SoA shared memory for source point tile
  __shared__ float sx[TILE_SIZE];
  __shared__ float sy[TILE_SIZE];
  __shared__ float sz[TILE_SIZE];

  const float *xyz_batch = xyz + bs_idx * n * 3;
  const float *new_xyz_batch = new_xyz + bs_idx * m * 3;
  int *idx_batch = idx + bs_idx * m * nsample;

  // Load query point coordinates into registers
  float qx = 0.0f, qy = 0.0f, qz = 0.0f;
  bool valid_query = (query_idx < m);
  if (valid_query) {
    qx = new_xyz_batch[query_idx * 3 + 0];
    qy = new_xyz_batch[query_idx * 3 + 1];
    qz = new_xyz_batch[query_idx * 3 + 2];
  }

  int cnt = 0;
  int *my_idx = valid_query ? (idx_batch + query_idx * nsample) : nullptr;

  int num_tiles = DIVUP(n, TILE_SIZE);

  for (int tile = 0; tile < num_tiles; ++tile) {
    // Cooperatively load source points into shared memory (SoA)
    int tile_offset = tile * TILE_SIZE;
    #pragma unroll 2
    for (int i = tid; i < TILE_SIZE; i += BLOCK_SIZE) {
      int src_idx = tile_offset + i;
      if (src_idx < n) {
        int base = src_idx * 3;
        sx[i] = xyz_batch[base + 0];
        sy[i] = xyz_batch[base + 1];
        sz[i] = xyz_batch[base + 2];
      }
    }
    __syncthreads();

    if (valid_query && cnt < nsample) {
      int tile_end = min(TILE_SIZE, n - tile_offset);

      for (int j = 0; j < tile_end; ++j) {
        float dx = qx - sx[j];
        float dy = qy - sy[j];
        float dz = qz - sz[j];
        float d2 = dx * dx + dy * dy + dz * dz;

        if (d2 < max_radius2) {
          int k = tile_offset + j;
          if (cnt == 0) {
            for (int l = 0; l < nsample; ++l) my_idx[l] = k;
          }
          my_idx[cnt] = k;
          if (++cnt >= nsample) break;
        }
      }
    }
    __syncthreads();
  }
}

// Dilated radius kernel (min_radius > 0)
__global__ __launch_bounds__(BLOCK_SIZE)
void ball_query_kernel_dilated(int b, int n, int m,
                                float min_radius2,
                                float max_radius2,
                                int nsample,
                                const float *__restrict__ new_xyz,
                                const float *__restrict__ xyz,
                                int *__restrict__ idx) {
  int bs_idx = blockIdx.y;
  if (bs_idx >= b) return;

  int tid = threadIdx.x;
  int query_idx = blockIdx.x * BLOCK_SIZE + tid;

  __shared__ float sx[TILE_SIZE];
  __shared__ float sy[TILE_SIZE];
  __shared__ float sz[TILE_SIZE];

  const float *xyz_batch = xyz + bs_idx * n * 3;
  const float *new_xyz_batch = new_xyz + bs_idx * m * 3;
  int *idx_batch = idx + bs_idx * m * nsample;

  float qx = 0.0f, qy = 0.0f, qz = 0.0f;
  bool valid_query = (query_idx < m);
  if (valid_query) {
    qx = new_xyz_batch[query_idx * 3 + 0];
    qy = new_xyz_batch[query_idx * 3 + 1];
    qz = new_xyz_batch[query_idx * 3 + 2];
  }

  int cnt = 0;
  int *my_idx = valid_query ? (idx_batch + query_idx * nsample) : nullptr;

  int num_tiles = DIVUP(n, TILE_SIZE);

  for (int tile = 0; tile < num_tiles; ++tile) {
    int tile_offset = tile * TILE_SIZE;
    #pragma unroll 2
    for (int i = tid; i < TILE_SIZE; i += BLOCK_SIZE) {
      int src_idx = tile_offset + i;
      if (src_idx < n) {
        int base = src_idx * 3;
        sx[i] = xyz_batch[base + 0];
        sy[i] = xyz_batch[base + 1];
        sz[i] = xyz_batch[base + 2];
      }
    }
    __syncthreads();

    if (valid_query && cnt < nsample) {
      int tile_end = min(TILE_SIZE, n - tile_offset);

      for (int j = 0; j < tile_end; ++j) {
        float dx = qx - sx[j];
        float dy = qy - sy[j];
        float dz = qz - sz[j];
        float d2 = dx * dx + dy * dy + dz * dz;

        if (d2 == 0.0f || (d2 >= min_radius2 && d2 < max_radius2)) {
          int k = tile_offset + j;
          if (cnt == 0) {
            for (int l = 0; l < nsample; ++l) my_idx[l] = k;
          }
          my_idx[cnt] = k;
          if (++cnt >= nsample) break;
        }
      }
    }
    __syncthreads();
  }
}

void ball_query_kernel_launcher(int b, int n, int m, float min_radius, float max_radius,
                                int nsample, const float *new_xyz, const float *xyz,
                                int *idx, hipStream_t stream) {
  dim3 blocks(DIVUP(m, BLOCK_SIZE), b);
  dim3 threads(BLOCK_SIZE);

  if (min_radius <= 0.0f) {
    float max_radius2 = max_radius * max_radius;
    ball_query_kernel_fixed<<<blocks, threads, 0, stream>>>(
        b, n, m, max_radius2, nsample, new_xyz, xyz, idx);
  } else {
    float min_radius2 = min_radius * min_radius;
    float max_radius2 = max_radius * max_radius;
    ball_query_kernel_dilated<<<blocks, threads, 0, stream>>>(
        b, n, m, min_radius2, max_radius2, nsample, new_xyz, xyz, idx);
  }

  hipError_t err = hipGetLastError();
  if (hipSuccess != err) {
    fprintf(stderr, "CUDA kernel failed : %s\n", hipGetErrorString(err));
    exit(-1);
  }
}

