+#include <hip/hip_runtime.h>
+#include <hip/hip_fp16.h>
+#include <hip/hip_bfloat16.h>
+#include <hip/amd_detail/amd_hip_fp8.h>
+#include <torch/extension.h>
+#include <ATen/cuda/CUDAContext.h>
+
+#define FP8_MAX 240.0f
+#define WARP_SIZE 64
+
+__device__ __forceinline__ float warp_reduce_sum(float val) {
+    #pragma unroll
+    for (int offset = WARP_SIZE/2; offset > 0; offset >>= 1)
+        val += __shfl_xor(val, offset, WARP_SIZE);
+    return val;
+}
+
+__device__ __forceinline__ float warp_reduce_max(float val) {
+    #pragma unroll
+    for (int offset = WARP_SIZE/2; offset > 0; offset >>= 1)
+        val = fmaxf(val, __shfl_xor(val, offset, WARP_SIZE));
+    return val;
+}
+
+template<int NUM_WARPS>
+__device__ __forceinline__ float block_reduce_sum(float val, float* smem, int tid) {
+    int warp_id = tid / WARP_SIZE;
+    int lane_id = tid % WARP_SIZE;
+    val = warp_reduce_sum(val);
+    if (lane_id == 0) smem[warp_id] = val;
+    __syncthreads();
+    if constexpr (NUM_WARPS == 1) {
+        return smem[0];
+    } else {
+        if (warp_id == 0) {
+            val = (lane_id < NUM_WARPS) ? smem[lane_id] : 0.0f;
+            val = warp_reduce_sum(val);
+        }
+        __syncthreads();
+        return val;
+    }
+}
+
+template<int NUM_WARPS>
+__device__ __forceinline__ float block_reduce_max(float val, float* smem, int tid) {
+    int warp_id = tid / WARP_SIZE;
+    int lane_id = tid % WARP_SIZE;
+    val = warp_reduce_max(val);
+    if (lane_id == 0) smem[warp_id] = val;
+    __syncthreads();
+    if constexpr (NUM_WARPS == 1) {
+        return smem[0];
+    } else {
+        if (warp_id == 0) {
+            val = (lane_id < NUM_WARPS) ? smem[lane_id] : 0.0f;
+            val = warp_reduce_max(val);
+        }
+        __syncthreads();
+        return val;
+    }
+}
+
+template<int BLOCK_THREADS, int GROUP_SIZE>
+__global__ __launch_bounds__(BLOCK_THREADS)
+void fused_rms_fp8_kernel(
+    const __hip_bfloat16* __restrict__ inp1,
+    const float* __restrict__ weight1,
+    const __hip_bfloat16* __restrict__ inp2,
+    const float* __restrict__ weight2,
+    const __hip_bfloat16* __restrict__ res1,
+    __hip_fp8_e4m3_fnuz* __restrict__ out1_fp8,
+    float* __restrict__ out1_bs,
+    __hip_bfloat16* __restrict__ out2,
+    __hip_bfloat16* __restrict__ out_res1,
+    __hip_bfloat16* __restrict__ out1_unq,
+    float eps1, float eps2,
+    int N1, int N2,
+    int inp1_stride, int inp2_stride, int res1_stride,
+    int fp8_stride, int bs_stride, int bs_col_stride,
+    int out2_stride, int res1_out_stride, int out1_stride,
+    bool has_res, bool has_unq, bool has_inp2
+) {
+    constexpr int NUM_WARPS = BLOCK_THREADS / WARP_SIZE;
+    int m = blockIdx.x;
+    int tid = threadIdx.x;
+    
+    __shared__ float smem[NUM_WARPS > 1 ? NUM_WARPS : 1];
+    
+    const __hip_bfloat16* row1 = inp1 + m * inp1_stride;
+    const __hip_bfloat16* row_res = has_res ? (res1 + m * res1_stride) : nullptr;
+    
+    // Pass 1: compute sum of squares
+    float sum_sq = 0.0f;
+    for (int n = tid; n < N1; n += BLOCK_THREADS) {
+        float x = static_cast<float>(row1[n]);
+        if (has_res) x += static_cast<float>(row_res[n]);
+        sum_sq += x * x;
+    }
+    
+    float total_sq = block_reduce_sum<NUM_WARPS>(sum_sq, smem, tid);
+    
+    __shared__ float s_norm;
+    if (tid == 0) s_norm = rsqrtf(total_sq / (float)N1 + eps1);
+    __syncthreads();
+    float norm_factor = s_norm;
+    
+    int num_groups = (N1 + GROUP_SIZE - 1) / GROUP_SIZE;
+    
+    __hip_fp8_e4m3_fnuz* fp8_row = out1_fp8 + m * fp8_stride;
+    float* bs_row = out1_bs + m * bs_stride;
+    __hip_bfloat16* unq_row = has_unq ? (out1_unq + m * out1_stride) : nullptr;
+    __hip_bfloat16* res_out_row = has_res ? (out_res1 + m * res1_out_stride) : nullptr;
+    
+    for (int g = 0; g < num_groups; g++) {
+        int g_start = g * GROUP_SIZE;
+        int g_end = min(g_start + GROUP_SIZE, N1);
+        
+        // Find max abs of normalized values
+        float local_max = 0.0f;
+        for (int n = g_start + tid; n < g_end; n += BLOCK_THREADS) {
+            float x = static_cast<float>(row1[n]);
+            if (has_res) x += static_cast<float>(row_res[n]);
+            float normed = x * norm_factor * weight1[n];
+            local_max = fmaxf(local_max, fabsf(normed));
+        }
+        
+        float group_max = block_reduce_max<NUM_WARPS>(local_max, smem, tid);
+        
+        __shared__ float s_scale, s_recip;
+        if (tid == 0) {
+            float mx = fmaxf(group_max, 1e-10f);
+            s_scale = mx / FP8_MAX;
+            s_recip = FP8_MAX / mx;
+        }
+        __syncthreads();
+        float scale_recip = s_recip;
+        
+        // Quantize and store
+        for (int n = g_start + tid; n < g_end; n += BLOCK_THREADS) {
+            float x = static_cast<float>(row1[n]);
+            if (has_res) {
+                float r = static_cast<float>(row_res[n]);
+                x += r;
+                res_out_row[n] = static_cast<__hip_bfloat16>(x);
+            }
+            float normed = x * norm_factor * weight1[n];
+            if (has_unq) unq_row[n] = static_cast<__hip_bfloat16>(normed);
+            float scaled = fminf(fmaxf(normed * scale_recip, -FP8_MAX), FP8_MAX);
+            fp8_row[n] = static_cast<__hip_fp8_e4m3_fnuz>(scaled);
+        }
+        
+        if (tid == 0) bs_row[g * bs_col_stride] = s_scale;
+        __syncthreads();
+    }
+    
+    if (has_inp2) {
+        const __hip_bfloat16* row2 = inp2 + m * inp2_stride;
+        __hip_bfloat16* out2_row = out2 + m * out2_stride;
+        
+        float sum_sq2 = 0.0f;
+        for (int n = tid; n < N2; n += BLOCK_THREADS)
+            sum_sq2 += static_cast<float>(row2[n]) * static_cast<float>(row2[n]);
+        float total_sq2 = block_reduce_sum<NUM_WARPS>(sum_sq2, smem, tid);
+        
+        __shared__ float s_norm2;
+        if (tid == 0) s_norm2 = rsqrtf(total_sq2 / (float)N2 + eps2);
+        __syncthreads();
+        float nf2 = s_norm2;
+        
+        for (int n = tid; n < N2; n += BLOCK_THREADS)
+            out2_row[n] = static_cast<__hip_bfloat16>(static_cast<float>(row2[n]) * nf2 * weight2[n]);
+    }
+}
+
+void launch_hip_kernel(
