+    auto* pw2 = has_inp2 ? weight2.data_ptr<float>() : nullptr;
+    auto* pr = has_res ? reinterpret_cast<const __hip_bfloat16*>(res1.data_ptr()) : nullptr;
+    auto* pfp8 = reinterpret_cast<__hip_fp8_e4m3_fnuz*>(out1_fp8.data_ptr());
+    auto* pbs = out1_bs.data_ptr<float>();
+    auto* po2 = has_inp2 ? reinterpret_cast<__hip_bfloat16*>(out2.data_ptr()) : nullptr;
+    auto* pro = has_res ? reinterpret_cast<__hip_bfloat16*>(out_res1.data_ptr()) : nullptr;
+    auto* pu = has_unq ? reinterpret_cast<__hip_bfloat16*>(out1.data_ptr()) : nullptr;
