index 0000000..b0506d3
--- /dev/null
+++ b/hip_rms_fp8.hip
@@ -0,0 +1,204 @@
+#include <hip/hip_runtime.h>
+#include <hip/hip_fp16.h>
+#include <hip/hip_bfloat16.h>
+#include <torch/extension.h>
+#include <ATen/cuda/CUDAContext.h>
+
+#define FP8_MAX 240.0f
+#define WARP_SIZE 64
+
+// Use the builtin to convert float to fp8 e4m3fnuz
+__device__ __forceinline__ unsigned char float_to_fp8(float val) {
+    // Pack two fp8 values, we only need the first one (byte 0)
+    unsigned int result = __builtin_amdgcn_cvt_pk_fp8_f32(val, 0.0f, 0, false);
+    return (unsigned char)(result & 0xFF);
+}
+
+__device__ __forceinline__ float warp_reduce_sum(float val) {
+    #pragma unroll
+    for (int offset = WARP_SIZE/2; offset > 0; offset >>= 1)
+        val += __shfl_xor(val, offset, WARP_SIZE);
+    return val;
+}
+
+__device__ __forceinline__ float warp_reduce_max(float val) {
+    #pragma unroll
+    for (int offset = WARP_SIZE/2; offset > 0; offset >>= 1)
+        val = fmaxf(val, __shfl_xor(val, offset, WARP_SIZE));
+    return val;
+}
+
+template<int NUM_WARPS>
+__device__ __forceinline__ float block_reduce_sum(float val, float* smem, int tid) {
+    int warp_id = tid / WARP_SIZE;
+    int lane_id = tid % WARP_SIZE;
+    val = warp_reduce_sum(val);
+    if (lane_id == 0) smem[warp_id] = val;
+    __syncthreads();
+    if constexpr (NUM_WARPS == 1) { return smem[0]; }
+    else {
+        if (warp_id == 0) {
+            val = (lane_id < NUM_WARPS) ? smem[lane_id] : 0.0f;
+            val = warp_reduce_sum(val);
+        }
+        __syncthreads();
+        return val;
+    }
+}
+
+template<int NUM_WARPS>
+__device__ __forceinline__ float block_reduce_max(float val, float* smem, int tid) {
+    int warp_id = tid / WARP_SIZE;
+    int lane_id = tid % WARP_SIZE;
+    val = warp_reduce_max(val);
+    if (lane_id == 0) smem[warp_id] = val;
+    __syncthreads();
+    if constexpr (NUM_WARPS == 1) { return smem[0]; }
+    else {
+        if (warp_id == 0) {
+            val = (lane_id < NUM_WARPS) ? smem[lane_id] : 0.0f;
+            val = warp_reduce_max(val);
+        }
+        __syncthreads();
+        return val;
+    }
+}
+
+template<int BT, int GS>
+__global__ __launch_bounds__(BT)
+void fused_rms_fp8_kern(
+    const __hip_bfloat16* __restrict__ inp1,
+    const float* __restrict__ w1,
+    const __hip_bfloat16* __restrict__ inp2,
+    const float* __restrict__ w2,
+    const __hip_bfloat16* __restrict__ res1,
+    unsigned char* __restrict__ ofp8,
+    float* __restrict__ obs,
+    __hip_bfloat16* __restrict__ o2,
+    __hip_bfloat16* __restrict__ ores,
+    __hip_bfloat16* __restrict__ ounq,
+    float eps1, float eps2,
+    int N1, int N2,
+    int s_i1, int s_i2, int s_r1,
+    int s_fp8, int s_bs, int s_bsc,
+    int s_o2, int s_or, int s_ou,
+    bool hr, bool hu, bool hi2
+) {
+    constexpr int NW = BT / WARP_SIZE;
+    int m = blockIdx.x;
+    int tid = threadIdx.x;
+    __shared__ float smem[NW > 1 ? NW : 1];
+    
+    const __hip_bfloat16* r1 = inp1 + m * s_i1;
+    const __hip_bfloat16* rr = hr ? (res1 + m * s_r1) : nullptr;
+    
+    // Sum of squares
+    float ssq = 0.0f;
+    for (int n = tid; n < N1; n += BT) {
+        float x = static_cast<float>(r1[n]);
+        if (hr) x += static_cast<float>(rr[n]);
+        ssq += x * x;
+    }
+    float tsq = block_reduce_sum<NW>(ssq, smem, tid);
+    
+    __shared__ float s_nf;
+    if (tid == 0) s_nf = rsqrtf(tsq / (float)N1 + eps1);
+    __syncthreads();
+    float nf = s_nf;
+    
+    int ng = (N1 + GS - 1) / GS;
+    unsigned char* fp8r = ofp8 + m * s_fp8;
+    float* bsr = obs + m * s_bs;
+    __hip_bfloat16* ur = hu ? (ounq + m * s_ou) : nullptr;
+    __hip_bfloat16* rr_out = hr ? (ores + m * s_or) : nullptr;
+    
+    for (int g = 0; g < ng; g++) {
+        int gs = g * GS;
+        int ge = min(gs + GS, N1);
+        
+        float lm = 0.0f;
+        for (int n = gs + tid; n < ge; n += BT) {
+            float x = static_cast<float>(r1[n]);
+            if (hr) x += static_cast<float>(rr[n]);
+            float normed = x * nf * w1[n];
+            lm = fmaxf(lm, fabsf(normed));
+        }
+        float gm = block_reduce_max<NW>(lm, smem, tid);
+        
+        __shared__ float s_sc, s_sr;
+        if (tid == 0) {
+            float mx = fmaxf(gm, 1e-10f);
+            s_sc = mx / FP8_MAX;
+            s_sr = FP8_MAX / mx;
+        }
+        __syncthreads();
+        float sr = s_sr;
+        
+        for (int n = gs + tid; n < ge; n += BT) {
+            float x = static_cast<float>(r1[n]);
+            if (hr) {
+                float rv = static_cast<float>(rr[n]);
+                x += rv;
+                rr_out[n] = static_cast<__hip_bfloat16>(x);
+            }
+            float normed = x * nf * w1[n];
+            if (hu) ur[n] = static_cast<__hip_bfloat16>(normed);
+            float scaled = fminf(fmaxf(normed * sr, -FP8_MAX), FP8_MAX);
+            fp8r[n] = float_to_fp8(scaled);
+        }
+        if (tid == 0) bsr[g * s_bsc] = s_sc;
+        __syncthreads();
+    }
+    
+    if (hi2) {
+        const __hip_bfloat16* r2 = inp2 + m * s_i2;
+        __hip_bfloat16* o2r = o2 + m * s_o2;
+        float ssq2 = 0.0f;
+        for (int n = tid; n < N2; n += BT) {
+            float v = static_cast<float>(r2[n]);
+            ssq2 += v * v;
+        }
+        float tsq2 = block_reduce_sum<NW>(ssq2, smem, tid);
+        __shared__ float s_nf2;
+        if (tid == 0) s_nf2 = rsqrtf(tsq2 / (float)N2 + eps2);
+        __syncthreads();
+        float nf2 = s_nf2;
+        for (int n = tid; n < N2; n += BT)
+            o2r[n] = static_cast<__hip_bfloat16>(static_cast<float>(r2[n]) * nf2 * w2[n]);
+    }
+}
+
+void launch_hip_kernel(
+    torch::Tensor i1, torch::Tensor w1, torch::Tensor i2, torch::Tensor w2, torch::Tensor r1,
+    torch::Tensor ofp8, torch::Tensor obs, torch::Tensor o2, torch::Tensor ores, torch::Tensor ou,
+    float e1, float e2, int M, int N1, int N2,
+    int si1, int si2, int sr1, int sfp8, int sbs, int sbsc,
+    int so2, int sor, int sou,
+    bool hr, bool hu, bool hi2
+) {
+    auto stream = at::cuda::getCurrentCUDAStream();
+    auto* p1 = reinterpret_cast<const __hip_bfloat16*>(i1.data_ptr());
+    auto* pw1 = w1.data_ptr<float>();
+    auto* p2 = hi2 ? reinterpret_cast<const __hip_bfloat16*>(i2.data_ptr()) : nullptr;
+    auto* pw2 = hi2 ? w2.data_ptr<float>() : nullptr;
+    auto* pr = hr ? reinterpret_cast<const __hip_bfloat16*>(r1.data_ptr()) : nullptr;
+    auto* pfp8 = reinterpret_cast<unsigned char*>(ofp8.data_ptr());
+    auto* pbs = obs.data_ptr<float>();
+    auto* po2 = hi2 ? reinterpret_cast<__hip_bfloat16*>(o2.data_ptr()) : nullptr;
+    auto* pro = hr ? reinterpret_cast<__hip_bfloat16*>(ores.data_ptr()) : nullptr;
+    auto* pu = hu ? reinterpret_cast<__hip_bfloat16*>(ou.data_ptr()) : nullptr;
+    
+    int maxN = max(N1, N2);
+    dim3 grid(M);
+    #define L(BT) fused_rms_fp8_kern<BT,128><<<grid,BT,0,stream>>>(p1,pw1,p2,pw2,pr,pfp8,pbs,po2,pro,pu,e1,e2,N1,N2,si1,si2,sr1,sfp8,sbs,sbsc,so2,sor,sou,hr,hu,hi2);
+    if (maxN <= 128) { L(64); }
+    else if (maxN <= 512) { L(128); }
+    else if (maxN <= 2048) { L(256); }
+    else if (maxN <= 4096) { L(512); }
+    else { L(1024); }
+    #undef L
+}
+
+PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
+    m.def("launch_hip_kernel", &launch_hip_kernel, "Fused RMSNorm + FP8 (HIP)");
+}
