+    out1_fp8_base = m_pid * out1_fp8_row_stride
+    tl.store(
+        out1_fp8_ptr + out1_fp8_base + n_offs,
+        out1_fp8.to(out1_fp8_ptr.dtype.element_ty), mask=mask1,
+    )
