+
+#define FP8_MAX 240.0f
+#define WARP_SIZE 64
+
+// Use the HIP builtin for proper FP8 e4m3fnuz conversion on device
+__device__ __forceinline__ uint8_t float_to_fp8_e4m3fnuz(float val) {
+    // Use __builtin_amdgcn_cvt_pk_fp8_f32 to convert float to fp8
+    // It packs two fp8 values; we use the same value twice and extract byte 0
+    union {
+        unsigned int i32;
+        unsigned char i8[4];
+    } result;
+    result.i32 = __builtin_amdgcn_cvt_pk_fp8_f32(val, val, 0, false);  // word=0, neg=false
+    return result.i8[0];
